            let widest = null;
            let widestW = clientW;
            for (const el of document.querySelectorAll('*')) {
                if (el.scrollWidth > widestW) {
                    widestW = el.scrollWidth;
                    widest = el.tagName + '.' + [...el.classList].join('.');
                }
            }
            return { scrollW, clientW, overflow: scrollW > clientW, widest, widestW };
        }""")

